-- Phase 12b: scrub-preview thumbnail sprites.
--
-- Each `media_files` row gets an optional companion sprite — a single JPEG
-- with one tile per N seconds of runtime laid out in a fixed grid. The
-- player computes `tile_index = position_s / interval_s` on hover and
-- renders the matching tile via `background-position` from the sprite.
-- Lazy-generated by the `generate_previews` scheduled task to keep scans
-- snappy.

ALTER TABLE media_files ADD COLUMN preview_sprite_path TEXT;
ALTER TABLE media_files ADD COLUMN preview_interval_ms INTEGER;
ALTER TABLE media_files ADD COLUMN preview_tile_width  INTEGER;
ALTER TABLE media_files ADD COLUMN preview_tile_height INTEGER;
ALTER TABLE media_files ADD COLUMN preview_tile_cols   INTEGER;
ALTER TABLE media_files ADD COLUMN preview_tile_count  INTEGER;
